use std::sync::Mutex;
use std::collections::HashMap;

struct Cache {
    data: Mutex<HashMap<String, String>>,
}

impl Cache {
    fn get(&self, key: &str) -> Option<String> {
        let map = self.data.lock().unwrap();
        map.get(key).cloned()
    }

    fn set(&self, key: String, value: String) {
        let mut map = self.data.lock().unwrap();
        map.insert(key, value);
    }
}
```

output:
[Medium] Unbounded-Growth: The HashMap has no size limit, potentially causing OOM in production.

[Medium] Unwrap-On-Poisoned-Mutex: `.lock().unwrap()` panics if another thread panicked while holding the lock, crashing the entire service.

[Low] No-TTL: Cached entries never expire.

Fix:
1. Use `.lock().unwrap_or_else(|e| e.into_inner())` to recover from poisoned mutex, or use `parking_lot::Mutex` which is unpoisonable
2. Add capacity limits with LRU eviction (e.g., `lru` crate)
3. Add TTL tracking with periodic cleanup
4. Consider `dashmap::DashMap` for better concurrent read performance

```rust
use dashmap::DashMap;
use std::time::{Instant, Duration};

struct Cache {
    data: DashMap<String, (String, Instant)>,
    ttl: Duration,
    max_size: usize,
}

impl Cache {
    fn get(&self, key: &str) -> Option<String> {
        self.data.get(key).and_then(|entry| {
            if entry.value().1.elapsed() < self.ttl {
                Some(entry.value().0.clone())
            } else {
                drop(entry);
                self.data.remove(key);
                None
            }
        })
    }
}
```

