Review this Rust code for security issues:
```rust
use std::fs;

fn serve_file(base_dir: &str, requested_path: &str) -> Option<Vec<u8>> {
    let full_path = format!("{}/{}", base_dir, requested_path);
    fs::read(&full_path).ok()
}
```

output:
[Critical] Path-Traversal: The `requested_path` is concatenated directly with `base_dir` without sanitization. An attacker can pass `../../etc/passwd` to read arbitrary files on the system.

Fix:
1. Canonicalize both paths and verify the resolved path is within `base_dir`
2. Reject paths containing `..` components

```rust
use std::path::{Path, PathBuf};
use std::fs;

fn serve_file(base_dir: &str, requested_path: &str) -> Option<Vec<u8>> {
    let base = Path::new(base_dir).canonicalize().ok()?;
    let resolved = base.join(requested_path).canonicalize().ok()?;

    if !resolved.starts_with(&base) {
        return None; // path traversal blocked
    }

    fs::read(&resolved).ok()
}
```

